// The code below implements PROPER JWT verification as required for any production system.

const express = require('express');
const session = require('express-session');
const { Issuer, generators } = require('openid-client');
const jwt = require('jsonwebtoken');
const jwksClient = require('jwks-rsa');

const app = express();

// Session configuration
app.use(session({
  secret: require('crypto').randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    maxAge: 3600000, // 1 hour
    sameSite: 'lax'
  }
}));

// Configuration - set these via environment variables
const CONFIG = {
  issuerUrl: process.env.OIDC_ISSUER_URL || 'https://accounts.google.com',
  clientId: process.env.OIDC_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.OIDC_CLIENT_SECRET || 'your-client-secret',
  redirectUri: process.env.OIDC_REDIRECT_URI || 'http://localhost:3000/callback',
  port: process.env.PORT || 3000
};

let oidcClient;
let jwksVerifier;

// Initialize the OIDC client and JWKS verifier
async function initialize() {
  try {
    const issuer = await Issuer.discover(CONFIG.issuerUrl);
    console.log('Discovered issuer:', issuer.metadata.issuer);

    oidcClient = new issuer.Client({
      client_id: CONFIG.clientId,
      client_secret: CONFIG.clientSecret,
      redirect_uris: [CONFIG.redirectUri],
      response_types: ['code'],
      token_endpoint_auth_method: 'client_secret_basic'
    });

    // Set up JWKS client for proper signature verification
    jwksVerifier = jwksClient({
      jwksUri: issuer.metadata.jwks_uri,
      cache: true,
      cacheMaxEntries: 5,
      cacheMaxAge: 600000 // 10 minutes
    });

    console.log('OIDC client initialized successfully');
  } catch (err) {
    console.error('Failed to initialize OIDC client:', err);
    process.exit(1);
  }
}

// Helper to get signing key from JWKS endpoint
function getSigningKey(header, callback) {
  jwksVerifier.getSigningKey(header.kid, (err, key) => {
    if (err) {
      return callback(err);
    }
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
}

// Properly verify and decode JWT with full signature verification
function verifyIdToken(idToken) {
  return new Promise((resolve, reject) => {
    jwt.verify(
      idToken,
      getSigningKey,
      {
        algorithms: ['RS256', 'RS384', 'RS512', 'ES256', 'ES384', 'ES512'],
        audience: CONFIG.clientId,
        issuer: CONFIG.issuerUrl,
        clockTolerance: 30 // 30 seconds clock skew tolerance
      },
      (err, decoded) => {
        if (err) {
          reject(new Error(`ID token verification failed: ${err.message}`));
        } else {
          // Additional validation checks
          const now = Math.floor(Date.now() / 1000);

          if (!decoded.sub) {
            reject(new Error('ID token missing required "sub" claim'));
            return;
          }

          if (decoded.exp && decoded.exp < now) {
            reject(new Error('ID token has expired'));
            return;
          }

          if (decoded.iat && decoded.iat > now + 30) {
            reject(new Error('ID token "iat" is in the future'));
            return;
          }

          resolve(decoded);
        }
      }
    );
  });
}

// Middleware to check if user is authenticated
function requireAuth(req, res, next) {
  if (req.session && req.session.user) {
    // Check if session has expired based on token expiry
    const now = Math.floor(Date.now() / 1000);
    if (req.session.user.tokenExp && req.session.user.tokenExp < now) {
      req.session.destroy();
      return res.redirect('/login');
    }
    return next();
  }
  res.redirect('/login');
}

