// Login route - initiates OIDC auth flow
app.get('/login', (req, res) => {
  const nonce = generators.nonce();
  const state = generators.state();

  // Store nonce and state in session for verification
  req.session.oidcNonce = nonce;
  req.session.oidcState = state;

  const authorizationUrl = oidcClient.authorizationUrl({
    scope: 'openid profile email',
    state: state,
    nonce: nonce,
    response_type: 'code'
  });

  res.redirect(authorizationUrl);
});

// Callback route - handles the OIDC response
app.get('/callback', async (req, res) => {
  try {
    const { code, state, error, error_description } = req.query;

    // Check for errors from the provider
    if (error) {
      console.error('OIDC error:', error, error_description);
      return res.status(400).send(`Authentication error: ${escapeHtml(error_description || error)}`);
    }

    // Verify state parameter to prevent CSRF
    if (!state || state !== req.session.oidcState) {
      return res.status(400).send('Invalid state parameter - possible CSRF attack');
    }

    if (!code) {
      return res.status(400).send('Missing authorization code');
    }

    // Exchange authorization code for tokens
    const params = oidcClient.callbackParams(req);
    const tokenSet = await oidcClient.callback(CONFIG.redirectUri, params, {
      nonce: req.session.oidcNonce,
      state: req.session.oidcState
    });

    const idToken = tokenSet.id_token;

    if (!idToken) {
      return res.status(400).send('No ID token received from provider');
    }

    // SECURE: Verify the JWT signature and validate all claims
    // NEVER use jwt.decode() without verification - it provides ZERO security
    const claims = await verifyIdToken(idToken);

    console.log('Successfully verified ID token for subject:', claims.sub);

    // Create user session from verified claims
    req.session.user = {
      sub: claims.sub,
      email: claims.email,
      emailVerified: claims.email_verified,
      name: claims.name,
      givenName: claims.given_name,
      familyName: claims.family_name,
      picture: claims.picture,
      locale: claims.locale,
      tokenExp: claims.exp,
      authenticatedAt: new Date().toISOString()
    };

    // Clean up OIDC session data
    delete req.session.oidcNonce;
    delete req.session.oidcState;

    // Regenerate session ID to prevent session fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration error:', err);
      }
      // Re-set user data after regeneration
      req.session.user = {
        sub: claims.sub,
        email: claims.email,
        emailVerified: claims.email_verified,
        name: claims.name,
        givenName: claims.given_name,
        familyName: claims.family_name,
        picture: claims.picture,
        locale: claims.locale,
        tokenExp: claims.exp,
        authenticatedAt: new Date().toISOString()
      };
      res.redirect('/');
    });

  } catch (err) {
    console.error('Callback error:', err.message);
    res.status(500).send(`Authentication failed: ${escapeHtml(err.message)}`);
  }
});

